        self.name = name; self.size = size; self.tint = tint
    }

    public var body: some View {
        let img = Image(name.rawValue, bundle: .module)
            .renderingMode(.template)
            .resizable()
            .aspectRatio(contentMode: .fit)
            .frame(width: size, height: size)
        if let tint = tint {
            return AnyView(img.foregroundColor(tint))
        }
        return AnyView(img)
    }
}
